            request.metrics().contains(Metric.FS)
                && featureService.clusterHasFeature(clusterService.state(), AllocationStatsFeatures.INCLUDE_DISK_THRESHOLD_SETTINGS)
                    ? diskThresholdSettings
                    : null
        )
    );
}

